  int
  main(int argc, char **argv)
  {
    /* .. */
	while ((ch = getopt(argc, argv, "d:gp")) != -1)
		switch (ch) {
		case 'd':
			if (*destdir == '\0')
				strlcpy(destdir, optarg, sizeof(destdir));
			else
				errx(2, "directory already set");
			break;
		case 'g':
			debugging++;
			break;
		case 'p':
			profiling++;
			break;
		case '?':
		default:
			usage();
		}
	argc -= optind;
    /* .. */
  }

